// BillingServiceServer is the server API for BillingService service.
// All implementations must embed UnimplementedBillingServiceServer
// for forward compatibility.
//
// BillingService provides billing and subscription management functionality.
type BillingServiceServer interface {
	SetupBilling(context.Context, *SetupBillingRequest) (*SetupBillingResponse, error)
	// Completes the billing setup process after Stripe payment workflow completion.
	//
	// Use this method to:
	// - Verify Stripe setup intent completion
	// - Create Metronome contract for the organization
	// - Grant free trial credits
	// - Finalize billing configuration
	//
	// ### Examples
	//
	// - Complete billing setup:
	//
	//	Finalizes billing after successful Stripe payment setup.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	setupIntentId: "seti_1234567890abcdef"
	//	```
	CompleteBillingSetup(context.Context, *CompleteBillingSetupRequest) (*CompleteBillingSetupResponse, error)
	// Retrieves billing information including credit balance for an organization.
	//
	// Use this method to:
	// - Check available credits for the organization
	// - Monitor credit usage and remaining balance
	// - Display billing status in the dashboard
	// - Implement usage-based alerts
	//
	// ### Examples
	//
	// - Get billing info:
	//
	//	Retrieves current credit balance and usage information.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	```
	GetBillingInfo(context.Context, *GetBillingInfoRequest) (*GetBillingInfoResponse, error)
	// Reconciles billing state for an organization.
	//
	// Use this method to:
	// - Ensure billing state is up-to-date with external providers (Stripe, Metronome)
	// - Sync organization tier based on active contracts
	// - Update credit status and payment failure state
	//
	// Call this when the user navigates to the billing page to ensure
	// they see the most current billing information.
	//
	// ### Examples
	//
	// - Reconcile billing:
	//
	//	Triggers billing reconciliation for the organization.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	```
	ReconcileBilling(context.Context, *ReconcileBillingRequest) (*ReconcileBillingResponse, error)
	// Creates a new subscription for an organization.
	//
	// Use this method to:
	// - Create a new subscription with specified type
	// - Add subscription to existing Metronome contract
	// - Create new contract if none exists
	CreateSubscription(context.Context, *CreateSubscriptionRequest) (*CreateSubscriptionResponse, error)
	// Cancels an existing subscription.
	//
	// Use this method to:
	// - Cancel active subscription
	// - Stop recurring billing
	// - Maintain access until end of billing period
	//
	// ### Examples
	//
	// - Cancel subscription:
	//
	//	Cancels the specified subscription.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	subscriptionType: SUBSCRIPTION_TYPE_CORE
	//	```
	CancelSubscription(context.Context, *CancelSubscriptionRequest) (*CancelSubscriptionResponse, error)
	// Updates an existing subscription's amount mid billing period, without cancellation.
	//
	// Use this method to:
	// - Change the subscription amount without cancelling and re-subscribing
	// - Switch between billing plans mid billing cycle
	UpdateSubscription(context.Context, *UpdateSubscriptionRequest) (*UpdateSubscriptionResponse, error)
	// Lists current subscriptions for an organization.
	//
	// Use this method to:
	// - View all active subscriptions
	// - Check subscription status and details
	// - Monitor subscription lifecycle
	//
	// ### Examples
	//
	// - List subscriptions:
	//
	//	Retrieves all subscriptions for the organization.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	```
	ListSubscriptions(context.Context, *ListSubscriptionsRequest) (*ListSubscriptionsResponse, error)
	// Grants additional credits to an organization.
	//
	// Use this method to:
	// - Grant credits to existing customers
	// - Add promotional credits
	// - Provide customer service credits
	//
	// ### Examples
	//
	// - Grant credits:
	//
	//	Grants 80 credits to the organization for one year.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	creditsAmount: 80.0
	//	```
	GrantCredits(context.Context, *GrantCreditsRequest) (*GrantCreditsResponse, error)
	// Retrieves the Stripe publishable key for an organization.
	//
	// Use this method to:
	// - Get the appropriate Stripe publishable key for frontend payment forms
	// - Support different billing realms (production/sandbox)
	// - Ensure proper isolation between organizations
	//
	// ### Examples
	//
	// - Get publishable key:
	//
	//	Retrieves the Stripe publishable key for the organization.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	```
	GetStripePublishableKey(context.Context, *GetStripePublishableKeyRequest) (*GetStripePublishableKeyResponse, error)
	// Sets the billing realm for an organization.
	//
	// Use this method to:
	// - Change organization's billing realm between sandbox and production
	// - Configure billing environment for the organization
	// - Requires Account permissions to perform the operation
	//
	// ### Examples
	//
	// - Set billing realm:
	//
	//	Changes organization billing realm to production.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	realm: BILLING_REALM_PRODUCTION
	//	```
	SetBillingRealm(context.Context, *SetBillingRealmRequest) (*SetBillingRealmResponse, error)
	// Creates a card verification entry for an account, allowing them to skip credit card verification.
	//
	// Use this method to:
	// - Grant Ona for Open Source program participants immediate access
	// - Mark pre-vetted accounts as credit card verified
	//
	// Requires the 'create_card_verification' account permission.
	//
	// ### Examples
	//
	// - Create card verification for open source maintainer:
	//
	//	```yaml
	//	email: "maintainer@example.org"
	//	```
	CreateCardVerification(context.Context, *CreateCardVerificationRequest) (*CreateCardVerificationResponse, error)
	// Sets or updates the tax ID for an organization.
	//
	// Use this method to:
	// - Set tax ID for billing purposes
	// - Update existing tax ID information
	// - Support various tax ID types (VAT, GST, etc.)
	//
	// ### Examples
	//
	// - Set EU VAT ID:
	//
	//	Sets a VAT ID for an EU organization.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	taxIdType: "eu_vat"
	//	taxIdValue: "DE123456789"
	//	```
	SetTaxID(context.Context, *SetTaxIDRequest) (*SetTaxIDResponse, error)
	// Gets details about a specific billing record.
	GetBillingRecord(context.Context, *GetBillingRecordRequest) (*GetBillingRecordResponse, error)
	// Updates a billing record
	UpdateBillingRecord(context.Context, *UpdateBillingRecordRequest) (*UpdateBillingRecordResponse, error)
	// Creates a new coupon for support staff to distribute to customers.
	//
	// Use this method to:
	// - Create promotional coupons for marketing campaigns
	// - Generate support coupons for customer service
	// - Set up trial credit coupons for new users
	CreateCoupon(context.Context, *CreateCouponRequest) (*CreateCouponResponse, error)
	// Lists existing coupons with filtering and pagination support.
	//
	// Use this method to:
	// - View all created coupons
	// - Filter coupons by status or type
	// - Monitor coupon usage and expiration
	ListCoupons(context.Context, *ListCouponsRequest) (*ListCouponsResponse, error)
	// Retrieves a specific coupon by its code.
	//
	// Use this method to:
	// - Validate coupon codes during checkout
	// - Display coupon details to users
	// - Check coupon availability and expiration
	//
	// ### Examples
	//
	// - Get coupon by code:
	//
	//	Retrieves coupon details for validation.
	//
	//	```yaml
	//	couponCode: "WELCOME2024"
	//	organizationId: "123e4567-e89b-12d3-a456-426614174000"
	//	```
	GetCoupon(context.Context, *GetCouponRequest) (*GetCouponResponse, error)
	// Sets or updates the billing address for an organization.
	//
	// Use this method to:
	// - Set billing address for tax calculation and compliance
	// - Update existing billing address information
	// - Support international billing requirements
	//
	// ### Examples
	//
	// - Set billing address:
	//
	//	Sets a complete billing address for the organization.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	name: "John Doe"
	//	address:
	//	  line1: "123 Main St"
	//	  line2: "Suite 100"
	//	  city: "San Francisco"
	//	  state: "CA"
	//	  postalCode: "94105"
	//	  country: "US"
	//	```
	SetBillingAddress(context.Context, *SetBillingAddressRequest) (*SetBillingAddressResponse, error)
	// Retrieves the Stripe Customer Portal URL for an organization.
	//
	// Use this method to:
	// - Get the Stripe Customer Portal URL for billing management
	// - Allow customers to manage their payment methods and billing details
	// - Provide access to billing history and invoices
	//
	// ### Examples
	//
	// - Get Stripe portal URL:
	//
	//	Retrieves the portal URL for the organization.
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	```
	GetStripePortalUrl(context.Context, *GetStripePortalUrlRequest) (*GetStripePortalUrlResponse, error)
	// Clears a topup payment failure for an organization.
	//
	// Use this method to:
	// - Acknowledge and clear a failed topup payment
	// - Allow the UI to return to normal state after user acknowledges the failure
	//
	// Unlike subscription failures which auto-resolve when payment succeeds,
	// topup failures need explicit user acknowledgment because the commit was
	// voided by Metronome and the user needs to retry with a working payment method.
	ClearTopupFailure(context.Context, *ClearTopupFailureRequest) (*ClearTopupFailureResponse, error)
	// Returns daily credit consumption (OCU) time series for an organization,
	// broken down by metric category.
	GetCreditConsumptionTimeSeries(context.Context, *GetCreditConsumptionTimeSeriesRequest) (*GetCreditConsumptionTimeSeriesResponse, error)
	// Sets up enterprise billing for an organization.
	//
	// Creates a Stripe customer, subscribes to the enterprise pricing plan,
	// and updates the billing realm. Idempotent — safe to retry on failure.
	//
	// Requires the 'change_billing_realm' account permission.
	//
	// ### Examples
	//
	// - Setup enterprise billing (production):
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	email: "billing@example.com"
	//	```
	//
	// - Setup enterprise billing (sandbox):
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	sandbox: true
	//	```
	SetupEnterpriseBilling(context.Context, *SetupEnterpriseBillingRequest) (*SetupEnterpriseBillingResponse, error)
	// Updates auto-topup settings for an organization.
	//
	// Use this method to:
	// - Enable or disable automatic credit top-ups
	// - Configure the top-up amount and threshold
	// - Set a daily safety cap on automatic top-ups
	//
	// Requires Core tier and the auto-topup feature flag.
	UpdateAutoTopupSettings(context.Context, *UpdateAutoTopupSettingsRequest) (*UpdateAutoTopupSettingsResponse, error)
	// Retrieves auto-topup settings for an organization.
	GetAutoTopupSettings(context.Context, *GetAutoTopupSettingsRequest) (*GetAutoTopupSettingsResponse, error)
	// Returns a daily credit usage report for an enterprise organization,
	// broken down by usage type and by user.
	GetCreditUsageReport(context.Context, *GetCreditUsageReportRequest) (*GetCreditUsageReportResponse, error)
	// Returns a signed download URL for a CSV export of per-user credit usage.
	// The URL points to an HTTP endpoint that streams gzip-compressed CSV.
	GetCreditUsageExport(context.Context, *GetCreditUsageExportRequest) (*GetCreditUsageExportResponse, error)
	// Returns organization-level enterprise AI usage totals for reporting.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	GetEnterpriseAIUsageSummary(context.Context, *GetEnterpriseAIUsageSummaryRequest) (*GetEnterpriseAIUsageSummaryResponse, error)
	// Lists enterprise AI usage grouped by team.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	ListEnterpriseAITeamUsage(context.Context, *ListEnterpriseAITeamUsageRequest) (*ListEnterpriseAITeamUsageResponse, error)
	// Lists enterprise AI usage grouped by user with effective monthly budget data.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	ListEnterpriseAIUserUsage(context.Context, *ListEnterpriseAIUserUsageRequest) (*ListEnterpriseAIUserUsageResponse, error)
	// Returns daily enterprise AI usage totals for the organization.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	GetEnterpriseAIUsageTimeSeries(context.Context, *GetEnterpriseAIUsageTimeSeriesRequest) (*GetEnterpriseAIUsageTimeSeriesResponse, error)
	// Corrects previously-synced usage events by cancelling the originals and
	// creating compensating negative-value events that flow through the normal
	// sync pipeline to Stripe. Internal admin operation.
	CorrectUsageEvents(context.Context, *CorrectUsageEventsRequest) (*CorrectUsageEventsResponse, error)
	// Inserts usage events from an external source (e.g., backfilling missing
	// LLM token usage from a provider console export). Internal admin operation.
	InsertUsageEvents(context.Context, *InsertUsageEventsRequest) (*InsertUsageEventsResponse, error)
	// Corrects environment_usage events for the given environment/time-range pairs.
	// Each EnvironmentCorrectionSpec identifies an environment and the window of
	// events to correct. Supports dry-run mode. Internal admin operation.
	CorrectEnvironmentUsageEvents(context.Context, *CorrectEnvironmentUsageEventsRequest) (*CorrectEnvironmentUsageEventsResponse, error)
	// Returns enterprise billing info for an organization.
	GetEnterpriseBillingInfo(context.Context, *GetEnterpriseBillingInfoRequest) (*GetEnterpriseBillingInfoResponse, error)
	// Returns the active BYOK rate-card entries for an enterprise organization.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	ListBYOKRateCardRates(context.Context, *ListBYOKRateCardRatesRequest) (*ListBYOKRateCardRatesResponse, error)
	// Creates a new effective BYOK rate-card version for a model and token type.
	//
	// Existing rates are immutable. Updating a model/token price creates a new
	// version with its own effective_at timestamp.
	//
	// ### Authorization
	//
	// Requires `billing:update` permission on the organization.
	SetBYOKRateCardRate(context.Context, *SetBYOKRateCardRateRequest) (*SetBYOKRateCardRateResponse, error)
	// Lists monthly user budget policies for enterprise AI usage.
	//
	// Returns the organization default separately from paginated per-user
	// overrides, making it easy for clients to show a global monthly budget and
	// the users that differ from it.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	ListEnterpriseAIUserBudgetPolicies(context.Context, *ListEnterpriseAIUserBudgetPoliciesRequest) (*ListEnterpriseAIUserBudgetPoliciesResponse, error)
	// Gets the configured and effective monthly budget policy for a user or org.
	//
	// When user_id is provided, the response includes any direct user override
	// and the effective policy after applying the organization default. When
	// user_id is omitted, both fields describe the organization default.
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	GetEnterpriseAIUserBudgetPolicy(context.Context, *GetEnterpriseAIUserBudgetPolicyRequest) (*GetEnterpriseAIUserBudgetPolicyResponse, error)
	// Sets the organization default or a per-user monthly budget policy.
	//
	// A user policy overrides the organization default. Set no_cap to exempt a
	// user from the default monthly budget.
	//
	// ### Authorization
	//
	// Requires `billing:update` permission on the organization.
	SetEnterpriseAIUserBudgetPolicy(context.Context, *SetEnterpriseAIUserBudgetPolicyRequest) (*SetEnterpriseAIUserBudgetPolicyResponse, error)
	// Deletes the organization default or a per-user monthly budget policy.
	//
	// ### Authorization
	//
	// Requires `billing:delete` permission on the organization.
	DeleteEnterpriseAIUserBudgetPolicy(context.Context, *DeleteEnterpriseAIUserBudgetPolicyRequest) (*DeleteEnterpriseAIUserBudgetPolicyResponse, error)
	// Requests a one-time recovery credit grant for an organization that is out of credits.
	// Grants a small amount of free credits so the user can start an environment and push
	// uncommitted work. Can only be used once per organization.
	RequestRecoveryCredit(context.Context, *RequestRecoveryCreditRequest) (*RequestRecoveryCreditResponse, error)
	// Returns cumulative credit usage for an organization and its teams.
	//
	// Use this method to:
	// - Get the total cumulative credit consumption as of a point in time
	// - Get per-team cumulative usage with credit allocation (budget) comparison
	// - Display team credit summaries on the usage page and team detail page
	// - Display user budget utilization when user budgets are enabled
	//
	// ### Examples
	//
	// - Get current cumulative usage:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	```
	//
	// - Get cumulative usage as of a specific date:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	asOf: "2026-03-31T23:59:59Z"
	//	```
	//
	// ### Authorization
	//
	// Requires `billing:read_usage` permission on the organization.
	GetCumulativeCreditUsage(context.Context, *GetCumulativeCreditUsageRequest) (*GetCumulativeCreditUsageResponse, error)
	// Lists per-user month-to-date credit usage with effective monthly budgets.
	//
	// Results are ordered by total credits descending so the highest spenders
	// appear first, with user_id as a stable tiebreaker. Use cursor pagination
	// to walk the full set for large organizations.
	//
	// ### Authorization
	//
	// Requires `billing:read` permission on the organization.
	ListEnterpriseUserCreditUsage(context.Context, *ListEnterpriseUserCreditUsageRequest) (*ListEnterpriseUserCreditUsageResponse, error)
	// Creates a credit allocation (budget) for a team.
	//
	// Allocations are soft budgets for reporting and alerting — not enforced at usage time.
	// Over-allocation (sum of team budgets > org grant) is allowed.
	//
	// ### Examples
	//
	// - Create a team allocation:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	teamId: "d2c94c27-3b76-4a42-b88c-95a85e392c68"
	//	creditBudget: "500"
	//	```
	//
	// ### Authorization
	//
	// Requires `billing:create` permission on the organization.
	CreateTeamCreditAllocation(context.Context, *CreateTeamCreditAllocationRequest) (*CreateTeamCreditAllocationResponse, error)
	// Gets the credit allocation for a team.
	//
	// ### Examples
	//
	// - Get a team's allocation:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	teamId: "d2c94c27-3b76-4a42-b88c-95a85e392c68"
	//	```
	//
	// ### Authorization
	//
	// Requires `billing:read` permission on the organization.
	GetTeamCreditAllocation(context.Context, *GetTeamCreditAllocationRequest) (*GetTeamCreditAllocationResponse, error)
	// Updates the credit allocation for a team.
	//
	// ### Examples
	//
	// - Update a team's budget:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	teamId: "d2c94c27-3b76-4a42-b88c-95a85e392c68"
	//	creditBudget: "750"
	//	```
	//
	// ### Authorization
	//
	// Requires `billing:update` permission on the organization.
	UpdateTeamCreditAllocation(context.Context, *UpdateTeamCreditAllocationRequest) (*UpdateTeamCreditAllocationResponse, error)
	// Deletes the credit allocation for a team.
	//
	// ### Examples
	//
	// - Delete a team's allocation:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	teamId: "d2c94c27-3b76-4a42-b88c-95a85e392c68"
	//	```
	//
	// ### Authorization
	//
	// Requires `billing:delete` permission on the organization.
	DeleteTeamCreditAllocation(context.Context, *DeleteTeamCreditAllocationRequest) (*DeleteTeamCreditAllocationResponse, error)
	// Sets the contracted credit grant for an organization.
	//
	// This is an admin-only operation for setting the total credit budget
	// allocated to an enterprise organization under their contract.
	//
	// ### Examples
	//
	// - Set credit grant:
	//
	//	```yaml
	//	organizationId: "b0e12f6c-4c67-429d-a4a6-d9838b5da047"
	//	creditGrant: "10000"
	//	```
	//
	// ### Authorization
	//
	// Requires `change_billing_realm` account permission.
	SetOrganizationCreditGrant(context.Context, *SetOrganizationCreditGrantRequest) (*SetOrganizationCreditGrantResponse, error)
	mustEmbedUnimplementedBillingServiceServer()
}

